/* 
-----------------------------------------------
Blogger Template Style
Name:        ten-dev-notes
License:     Free Version
Version:     1.0
Author:      ten-dev-notes
Author Url:  https://ten-dev-notes.blogspot.com/
----------------------------------------------- */


/*
<!-- Variable definitions -->
<Variable name="keycolor" description="Main Color" type="color" default="$(main.color)" value="#4776e6"/>
<Variable name="followByEmail" description="Follow By Email Text" type="string" default="Get all latest content delivered straight to your inbox." value="Get all latest content delivered straight to your inbox."/>

<Group description="Theme Colors" selector="body">
 <Variable name="main.color" description="Theme Color" type="color" default="#4776e6" value="#4776e6"/>
  <Variable name="main.dark.color" description="Dark Color" type="color" default="#000000" value="#000000"/>
  <Variable name="title.color" description="Title Color" type="color" default="#000000" value="#000000"/>
  <Variable name="title.hover" description="Title Color on Hover" type="color" default="$(main.color)" value="#4776e6"/>
</Group>

<Group description="Theme Body" selector="body">
  <Variable name="body.background.color" description="Body Background Color" type="color" default="#dee3ff"  value="#dee3ff"/>
  <Variable name="body.background" description="Background" type="background" color="$(body.background.color)" default="$(color) url() repeat fixed top left" value="$(color) url() repeat fixed top left"/>
  <Variable name="body.text.color" description="Text Color" type="color" default="#444444"  value="#444444"/>
  <Variable name="body.link.color" description="Link Color" type="color" default="$(main.color)"  value="#4776e6"/>
</Group>

<Group description="Main Menu" selector="body">
  <Variable name="menu.bg" description="Menu Background Color" type="color" default="transparent"  value="transparent"/>
  <Variable name="menu.color" description="Menu Text Color" type="color" default="#ffffff"  value="#ffffff"/>
  <Variable name="menu.hover" description="Menu Hover Color" type="color" default="$(main.color)"  value="#4776e6"/>
</Group>

<Group description="Sub Menu Colors" selector="body">
  <Variable name="submenu.bg" description="Sub Menu Background" type="color" default="#ffffff" value="#ffffff"/>
  <Variable name="submenu.color" description="Sub Menu Color" type="color" default="$(main.dark.color)"  value="#26292c"/>
  <Variable name="submenu.hover" description="Sub Menu Hover" type="color" default="$(main.color)" value="#fbc02d"/>
</Group>

 <Group description="Intro Section" selector="#main-intro">
  <Variable name="intro.title" description="Intro Title Color" type="color" default="#ffffff" value="#ffffff"/>
  <Variable name="intro.hg" description="Intro Title Highlight" type="color" default="#eb2a2a" value="#eb2a2a"/>
  <Variable name="intro.text" description="Intro Text Color" type="color" default="#e0e0e0" value="#e0e0e0"/>
</Group>
<Group description="Top Menu" selector="body">
  <Variable name="top.menu.color" description="Top Menu Color" type="color" default="#ffffff"  value="#ffffff"/>
  <Variable name="top.menu.hover" description="Top Menu Hover" type="color" default="$(main.color)"  value="#4776e6"/>
</Group>

<Group description="Top Social" selector="body">
  <Variable name="top.social.color" description="Top Social Color" type="color" default="#ffffff"  value="#ffffff"/>
  <Variable name="top.social.hover" description="Top Social Hover" type="color" default="$(main.color)"  value="#4776e6"/>
</Group>
<Group description="Slider Widget" selector="body">
  <Variable name="slider.body" description="Slider Background" type="color" default="#ffffff"  value="#ffffff"/>
</Group>
<Group description="Featured Post Colors" selector="body">
  <Variable name="feat.bg" description="Featured Post Background" type="color" default="#ffffff" value="#ffffff"/>
  <Variable name="feat.color" description="Featured Title Color" type="color" default="$(title.color)" value="#203656"/>
  <Variable name="feat.hover" description="Featured Title Hover" type="color" default="$(main.color)" value="#fe4f70"/>
  <Variable name="feat.button.bg" description="Featured Button Background" type="color" default="$(main.dark.color)" value="#203656"/>
  <Variable name="feat.button.color" description="Featured Button Color" type="color" default="#ffffff" value="#ffffff"/>
  <Variable name="feat.button.hover" description="Featured Button Hover" type="color" default="$(main.color)" value="#fe4f70"/>
</Group>
<Group description="Grid Wrapper" selector="body">
  <Variable name="grid.bg" description="Footer Background Color" type="color" default="#ffffff"  value="#ffffff"/>
  <Variable name="grid.color" description="Footer Text Color" type="color" default="$(main.dark.color)" value="#203656"/>
  <Variable name="grid.hover" description="Footer Hover Color" type="color" default="$(main.color)"  value="#4776e6"/>
</Group>
<Group description="Footer" selector="body">
  <Variable name="footer.bg" description="Footer Background Color" type="color" default="$(main.dark.color)"  value="#26292c"/>
  <Variable name="footer.color" description="Footer Text Color" type="color" default="#ffffff"  value="#ffffff"/>
  <Variable name="footer.hover" description="Footer Hover Color" type="color" default="$(main.color)"  value="#4776e6"/>
</Group>

<!-- Extra Variables -->
<Variable name="body.text.font" description="Font" hideEditor="true" type="font" default="14px Merriweather"  value="14px Merriweather"/>
<Variable name="posts.background.color" description="Post background color" hideEditor="true" type="color" default="#ffffff"  value="#ffffff"/>
<Variable name="tabs.font" description="Font 2" hideEditor="true" type="font" default="14px Merriweather"  value="14px Merriweather"/>
<Variable name="posts.title.color" description="Post title color" hideEditor="true" type="color" default="#000000"  value="#000000"/>
<Variable name="posts.text.color" description="Post text color" hideEditor="true" type="color" default="#656565"  value="#656565"/>
<Variable name="posts.icons.color" description="Post icons color" hideEditor="true" type="color" default="$(main.color)"  value="#EAB543"/>
<Variable name="labels.background.color" description="Label background color" hideEditor="true" type="color" default="$(main.color)"  value="#EAB543"/>
*/

