b:includable.script:
var disqus_blogger_current_url = "";
if (!disqus_blogger_current_url.length) {
  disqus_blogger_current_url = "";
}
var disqus_blogger_homepage_url = "";
var disqus_blogger_canonical_homepage_url = "";

b:if.script:
//
// Pagination state. Globals are intentional — inline onclick handlers in the
// rendered pager need to call getPage/getLabelPage.
let postResults = postPerPage;
let numOfPages = 2;
const pageOf = ["Page", "of"];
let noPage;
let currentPage;
let currentPageNo;
let postLabel;
const HOME = "/";

function startPagination(totalResults) {
  const half = Math.floor(numOfPages / 2);
  if (half === numOfPages - half) numOfPages = half * 2 + 1;
  let pageStart = currentPageNo - half;
  if (pageStart < 1) pageStart = 1;
  let lastPageNo = Math.floor(totalResults / postResults) + 1;
  if (lastPageNo - 1 === totalResults / postResults) lastPageNo -= 1;
  let pageEnd = pageStart + numOfPages - 1;
  if (pageEnd > lastPageNo) pageEnd = lastPageNo;

  const parts = [];
  parts.push(`<span class="page-of">${pageOf[0]} ${currentPageNo} ${pageOf[1]} ${lastPageNo}</span>`);

  const prev = Number(currentPageNo) - 1;
  if (currentPageNo > 1) {
    if (Number(currentPageNo) === 2) {
      const href = currentPage === 'page' ? HOME : `/search/label/${postLabel}?&max-results=${postResults}`;
      parts.push(`<a class="page-num page-prev" href="${href}"></a>`);
    } else {
      const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
      parts.push(`<a class="page-num page-prev" href="#" onclick="${fn}(${prev});return false"></a>`);
    }
  }

  if (pageStart > 1) {
    const href = currentPage === 'page' ? HOME : `/search/label/${postLabel}?&max-results=${postResults}`;
    parts.push(`<a class="page-num" href="${href}">1</a>`);
  }
  if (pageStart > 2) parts.push('<span class="page-num page-dots">...</span>');

  for (let d = pageStart; d <= pageEnd; d++) {
    if (Number(currentPageNo) === d) {
      parts.push(`<span class="page-num page-active">${d}</span>`);
    } else if (d === 1) {
      const href = currentPage === 'page' ? HOME : `/search/label/${postLabel}?&max-results=${postResults}`;
      parts.push(`<a class="page-num" href="${href}">1</a>`);
    } else {
      const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
      parts.push(`<a class="page-num" href="#" onclick="${fn}(${d});return false">${d}</a>`);
    }
  }

  if (pageEnd < lastPageNo - 1) parts.push('<span class="page-num page-dots">...</span>');
  if (pageEnd < lastPageNo) {
    const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
    parts.push(`<a class="page-num" href="#" onclick="${fn}(${lastPageNo});return false">${lastPageNo}</a>`);
  }

  const next = Number(currentPageNo) + 1;
  if (currentPageNo < lastPageNo) {
    const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
    parts.push(`<a class="page-num page-next" href="#" onclick="${fn}(${next});return false"></a>`);
  }

  const html = parts.join('');
  const areas = document.querySelectorAll('[name="pageArea"]');
  const pager = document.getElementById('blog-pager');
  areas.forEach(area => { area.innerHTML = html; });
  if (pager && areas.length === 0) pager.innerHTML = html;
}

function dataFeed(data) {
  const total = parseInt(data.feed.openSearch$totalResults.$t, 10);
  startPagination(total);
}

function pageCurrentBlogger() {
  const url = location.href;
  if (url.indexOf('/search/label/') !== -1) {
    const labelStart = url.indexOf('/search/label/') + 14;
    const labelEnd = url.indexOf('?updated-max') !== -1 ? url.indexOf('?updated-max') : url.indexOf('?&max');
    postLabel = url.substring(labelStart, labelEnd);
  }
  if (url.indexOf('?q=') !== -1 || url.indexOf('.html') !== -1) return;

  const pageNoIdx = url.indexOf('#PageNo=');
  currentPageNo = pageNoIdx !== -1 ? url.substring(pageNoIdx + 8) : 1;

  if (url.indexOf('/search/label/') === -1) {
    currentPage = 'page';
    fetchFeed(`${HOME}feeds/posts/summary?max-results=1&alt=json`).then(dataFeed);
  } else {
    currentPage = 'label';
    if (url.indexOf('&max-results=') === -1) postResults = 20;
    fetchFeed(`${HOME}feeds/posts/summary/-/${postLabel}?alt=json&max-results=1`).then(dataFeed);
  }
}

function fetchFeed(url) {
  return fetch(url).then(r => r.json());
}

function getPage(page) {
  const jsonstart = (page - 1) * postResults;
  noPage = page;
  fetchFeed(`${HOME}feeds/posts/summary?start-index=${jsonstart}&max-results=1&alt=json`).then(findPostDate);
}

function getLabelPage(page) {
  const jsonstart = (page - 1) * postResults;
  noPage = page;
  fetchFeed(`${HOME}feeds/posts/summary/-/${postLabel}?start-index=${jsonstart}&max-results=1&alt=json`).then(findPostDate);
}

function findPostDate(data) {
  const post = data.feed.entry[0];
  const ts = encodeURIComponent(post.published.$t.substring(0, 19) + post.published.$t.substring(23, 29));
  const url = currentPage === 'page'
    ? `/search?updated-max=${ts}&max-results=${postResults}#PageNo=${noPage}`
    : `/search/label/${postLabel}?updated-max=${ts}&max-results=${postResults}#PageNo=${noPage}`;
  location.href = url;
}

pageCurrentBlogger();
//
